class EightPuzzleAgent extends ProblemSolvingAgent {
    public EightPuzzleAgent(int[] initial, int[] goal) {
        super(initial, goal);
    }

    @Override
    public boolean isGoal(Object state) {
        // Check if current state equals goal state
        return Arrays.equals((int[])state, (int[])goalState);
    }

    @Override
    public List<Object> getSuccessors(Object state) {
        // Generate all valid moves from current state
        // Returns list of new states
        return new ArrayList<>();
    }

    @Override
    public double pathCost(List<Object> path) {
        return path.size();  // Each move costs 1
    }
}
